#include <iostream>
#include <parlay/primitives.h>
#include <sstream>
#include <iomanip>
#include <limits>
#include <cmath>
#include <cassert>
#include <string>

int main() {
 // begin of LLM generated code

auto convert_std = [](float x) {
  std::stringstream ss;
  ss << std::setprecision(7) << x;
  return std::stof(ss.str());
};

auto convert_parlay = [](float x) {
  std::stringstream ss;
  ss << std::setprecision(7) << x;
  // Use parlay::to_chars to get the char sequence from the stringstream string,
  // then parlay::chars_to_float to parse it back to float.
  return parlay::chars_to_float(parlay::to_chars(ss.str()));
};

// Example usage demonstrating the conversion process derived from the test:
float zero_f = 0.0f;
float converted_zero = convert_parlay(zero_f);

float large_f = 1.23e9f;
float converted_large = convert_parlay(large_f);

float negative_int_f = -100000.0f;
float converted_negative_int = convert_parlay(negative_int_f);

 // end of LLM generated code

 // Add test assertions here, using `assert()` and not `ASSERT_EQ`

  // Test the corner cases
  assert(convert_std(0.0f) == convert_parlay(0.0f));

  // 1.000001 * is required since converting to a string rounds towards zero, which will take min below the range of representable values!
  assert(convert_std(1.000001f * (std::numeric_limits<float>::min)()) == convert_parlay(1.000001f * (std::numeric_limits<float>::min)()));
  assert(convert_std(-1.000001f * (std::numeric_limits<float>::min)()) == convert_parlay(-1.000001f * (std::numeric_limits<float>::min)()));
  assert(convert_std(std::numeric_limits<float>::lowest()) == convert_parlay(std::numeric_limits<float>::lowest()));
  assert(convert_std((std::numeric_limits<float>::max)()) == convert_parlay((std::numeric_limits<float>::max)()));

  if (std::numeric_limits<float>::has_infinity) {
    // Need to convert inf to string then back for parlay to parse it
    std::stringstream ss_inf;
    ss_inf << std::numeric_limits<float>::infinity();
    auto inf_str = ss_inf.str();
    assert(std::isinf(parlay::chars_to_float(parlay::to_chars(inf_str))));
  }
  if (std::numeric_limits<float>::has_quiet_NaN) {
     // Need to convert NaN to string then back for parlay to parse it
    std::stringstream ss_nan;
    ss_nan << std::numeric_limits<float>::quiet_NaN();
    auto nan_str = ss_nan.str();
    assert(std::isnan(parlay::chars_to_float(parlay::to_chars(nan_str))));
  }

  // Test some random floats
  for (float x = -1.3e9; x < 1.3e9; x+= 3.1415e5) {
    assert(convert_std(x) == convert_parlay(x));
  }

  // Test some whole numbers
  for (int x = -2000000; x < 2000000; x += 31) {
    float y = static_cast<float>(x);
    assert(convert_std(y) == convert_parlay(y));
  }

 std::cout << "Test passed!" << std::endl;}

