#include <parlay/internal/hazptr/hazptr_stack.h>
#include <iostream>
#include <parlay/primitives.h>
#include <atomic>
#include <optional>

int main() {
 constexpr int M = 100000;

 long long checksum1 = 0;
 long long checksum2 = 0;
 long long actualsum1 = 0;
 long long actualsum2 = 0;

 parlay::internal::hazptr_stack<int> stack;
 std::atomic<bool> done1 = false;
 std::atomic<bool> done2 = false;

 std::atomic<int> tid(1);

 parlay::parallel_for(0, 4, [&](size_t) {
   int t = tid.fetch_add(1);
   if (t == 1) {
     for(int i = 0; i < M; i++) {
       stack.push(i);
       actualsum1 += i;
     }
     done1 = true;
   }
   else if (t == 2) {
     for(int i = 0; i < M; i++) {
       stack.push(i);
       actualsum2 += i;
     }
     done2 = true;
   }
   else if (t == 3) {
     while(!done1 || !done2 || !stack.empty()) {
       auto val = stack.pop();
       if (val) checksum1 += val.value();
     }
   }
   else {
     while(!done1 || !done2 || !stack.empty()) {
       auto val = stack.pop();
       if (val) checksum2 += val.value();
     }
   }
 }, 1);

 assert(stack.empty());
 assert(checksum1 + checksum2 == actualsum1 + actualsum2);

 std::cout << "Test passed!" << std::endl;
 return 0;
}

