// Define UncopyableThing struct
struct UncopyableThing {
    int x;
    // Constructor
    UncopyableThing(int val) : x(val) {}

    // Deleted copy constructor and copy assignment operator
    UncopyableThing(const UncopyableThing&) = delete;
    UncopyableThing& operator=(const UncopyableThing&) = delete;

    // Move constructor and move assignment operator
    UncopyableThing(UncopyableThing&& other) noexcept : x(other.x) {
        other.x = -1; // Example: invalidate moved-from object
    }
    UncopyableThing& operator=(UncopyableThing&& other) noexcept {
        if (this != &other) {
            x = other.x;
            other.x = -1; // Example: invalidate moved-from object
        }
        return *this;
    }

    // Default constructor needed by some parlay operations (like resize/tabulate)
    UncopyableThing() : x(0) {}

    // Comparison operators for assertions and std::sort
    bool operator==(const UncopyableThing& other) const {
        return x == other.x;
    }
    bool operator<(const UncopyableThing& other) const {
        return x < other.x;
    }
};

