  bool operator<(const UnstablePair& other) const {
    // Sort primarily by x. y is ignored for comparison, crucial for stability tests.
    return x < other.x;
  }

  // operator== is required for vector comparison
  bool operator==(const UnstablePair& other) const {
      return x == other.x && y == other.y;
  }
};

