int main() {
 // begin of LLM generated code
  auto s = parlay::tabulate(100000, [](long long i) -> long long {
    return (50021 * i + 61) % (1 << 20);
  });
  auto total = parlay::scan_inplace(s);
 // end of LLM generated code

 // Add test assertions here, using `assert()` and not `ASSERT_EQ`
  // Recreate original sequence for validation
  auto original_s = parlay::tabulate(100000, [](long long i) -> long long {
    return (50021 * i + 61) % (1 << 20);
  });
  // Calculate expected total sum
  auto sum = std::accumulate(std::begin(original_s), std::end(original_s), 0LL);
  // Calculate expected exclusive partial sums as done in the original test
  auto test_psums = parlay::sequence<long long>(100000);
  // test_psums[0] will be 0 (default initialization)
  // std::partial_sum(..., out+1) makes out[i+1] = sum of first i elements of input range
  // This aligns with exclusive scan: test_psums[i] = sum of original_s[0]...original_s[i-1]
  std::partial_sum(std::begin(original_s), std::end(original_s)-1, std::begin(test_psums)+1);

  // Check if the sequence s now holds the expected exclusive prefix sums
  assert(s == test_psums);
  // Check if the returned total is correct
  assert(total == sum);

  std::cout << "Test passed!" << std::endl;
  return 0;
}

