// BasicMatrix needs operator==()

// Mock implementations for the test
#ifndef BASIC_MATRIX_H
#define BASIC_MATRIX_H

template<typename T, int N>
struct BasicMatrix {
    T data[N][N];

    BasicMatrix() {
        for (int i = 0; i < N; ++i) for (int j = 0; j < N; ++j) data[i][j] = 0;
    }

    static BasicMatrix zero() { return BasicMatrix(); }

    bool operator==(const BasicMatrix& other) const {
        for (int i = 0; i < N; ++i) for (int j = 0; j < N; ++j) if (data[i][j] != other.data[i][j]) return false;
        return true;
    }
};

template<int N>
BasicMatrix<int,N> matrix_add(BasicMatrix<int,N> a, const BasicMatrix<int,N>& b) {
    for (int i = 0; i < N; ++i) for (int j = 0; j < N; ++j) a.data[i][j] += b.data[i][j];
    return a;
}

parlay::sequence<BasicMatrix<int,3>> get_matrices() {
    parlay::sequence<BasicMatrix<int,3>> s(5);
    for (int i = 0; i < 5; ++i) {
        for (int r = 0; r < 3; ++r) for (int c = 0; c < 3; ++c) s[i].data[r][c] = (i + 1) * (r * 3 + c + 1);
    }
    return s;
}

#endif // BASIC_MATRIX_H

