// Simple BasicMatrix definition for testing purposes
template <typename T, size_t N>
struct BasicMatrix {
    T data[N][N];

    BasicMatrix() {
        for (size_t i = 0; i < N; ++i) {
            for (size_t j = 0; j < N; ++j) {
                data[i][j] = T(); // Zero initialization
            }
        }
    }

    T& operator()(size_t r, size_t c) { return data[r][c]; }
    const T& operator()(size_t r, size_t c) const { return data[r][c]; }

    bool operator==(const BasicMatrix<T, N>& other) const {
        for (size_t i = 0; i < N; ++i) {
            for (size_t j = 0; j < N; ++j) {
                if (data[i][j] != other.data[i][j]) return false;
            }
        }
        return true;
    }

     bool operator!=(const BasicMatrix<T, N>& other) const {
        return !(*this == other);
    }

    // Static zero method
    static BasicMatrix<T, N> zero() {
        return BasicMatrix<T, N>();
    }
};

// Simple matrix_add function for testing purposes
template <size_t N, typename T>
BasicMatrix<T, N> matrix_add(const BasicMatrix<T, N>& a, const BasicMatrix<T, N>& b) {
    BasicMatrix<T, N> result;
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = 0; j < N; ++j) {
            result(i, j) = a(i, j) + b(i, j);
        }
    }
    return result;
}

